import { Box, Button, Dialog } from '@mui/material'
import React, { useEffect, useState } from 'react'
import Localizations from '../../locales/fa/fa.xml'
const ReportDialog = props => {
    const {reportLabel,reportFile, reportData} = props
    const [open, setOpen] = useState(false)
      useEffect(()=>{

    window.Stimulsoft.Base.StiLicense.Key =""
    window.Stimulsoft.Base.Localization.StiLocalization.setLocalizationFile(Localizations, true);
   var report = new window.Stimulsoft.Report.StiReport();
   // report.licenseKey =""
 
   report.loadFile(reportFile);
   //Stimulsoft.Base.StiLicense.Key =""
   var options = new window.Stimulsoft.Viewer.StiViewerOptions();
   var viewer = new window.Stimulsoft.Viewer.StiViewer(
     options,
     "StiViewer",
     false
   );
 
     var dataSet = new window.Stimulsoft.System.Data.DataSet("ElectProjectDetail");
    const JsonData = {
      ElectProjectDetail:reportData
    }
    dataSet.readJson(JsonData);
     report.dictionary.databases.clear();
 
     report.regData("ElectProjectDetail", "ElectProjectDetail", dataSet);
 
   viewer.report = report;
    viewer.stiRightToLeftType = true;
   viewer.renderHtml("viewer");
 },[])


  return (
    <Box>
        <Button
               variant="contained"
               color="primary"
               size="small"
               style={{}}
               onClick={async () => {
      
                setOpen(!open)
              }}
        >
            {reportLabel}
        </Button>

        <Dialog
        open={open}
        onClose={()=>{
            setOpen(false)
        }}
        >
    <div  id='viewer'></div>
        </Dialog>
    </Box>

  )
}

export default ReportDialog